import java.util.Objects;
public class Position { public int row, col; public Position(int r, int c) { this.row = r; this.col = c; } public static Position fromAlgebraic(String s) { s=s.trim(); int col=s.charAt(0)-'a'; int row=8-Character.getNumericValue(s.charAt(1)); return new Position(row,col);} public String toAlgebraic(){return ""+(char)('a'+col)+(8-row);} @Override public boolean equals(Object o){ if(!(o instanceof Position)) return false; Position p=(Position)o; return p.row==row && p.col==col;} @Override public int hashCode(){return Objects.hash(row,col);} @Override public String toString(){return toAlgebraic();} }